__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"inspirationCategories",{enumerable:!0,get:function(){return n}});const n=[{key:'first-aid',title:'Prvn\xed pomoc',subtitle:'Z\xe1kladn\xed postupy pro tren\xe9ry',icon:'plus-square',accent:'#F0445B',intro:'Obsah je zpracov\xe1n v souladu s ERC Guidelines 2025 (European Resuscitation Council), doporu\u010den\xedmi ILCOR 2025 a aktu\xe1ln\xedm konsensem AHA/ERC pro laick\xe9 poskytovatele prvn\xed pomoci. Postupy jsou p\u0159izp\u016fsobeny kontextu d\u011btsk\xe9ho sportovn\xedho tr\xe9ninku (parkour, freerunning, gymnastika).',sourceNote:'Zdroje obsahu prvn\xed pomoci: ERC Guidelines 2025 First Aid (Dj\xe4rv et al., Resuscitation 2025), ILCOR CoSTR 2025, AHA/AAP 2025 Choking Guidelines, PEACE & LOVE protokol (Dubois & Esculier, BJSM 2020)',items:[{id:'fa-general',title:'Obecn\xe9 z\xe1sady',summary:'Zachovejte klid, jednejte rychle a s rozvahou.',tags:['Z\xe1klad','ABCDE'],content:"- Zachovejte klid, jednejte rychle a s rozvahou.\n- Nejprve v\u017edy zajist\u011bte bezpe\u010dnost prost\u0159ed\xed \u2014 pro zran\u011bn\xe9ho i ostatn\xed d\u011bti.\n- Pokud si nejste jisti stavem d\xedt\u011bte, volejte 155 / 112. Ide\xe1ln\u011b na hlasit\xfd reproduktor, abyste mohli pom\xe1hat sou\u010dasn\u011b.\n- Nikdy nepodce\u0148ujte ani zd\xe1nliv\u011b lehk\xe9 p\u0159\xedznaky.\n- Pou\u017e\xedvejte jen vybaven\xed a postupy, ve kter\xfdch jste pro\u0161koleni.\n- P\u0159istupujte k posti\u017een\xe9mu strukturovan\u011b: ABCDE (A \u2013 d\xfdchac\xed cesty, B \u2013 d\xfdch\xe1n\xed, C \u2013 ob\u011bh, D \u2013 v\u011bdom\xed, E \u2013 celkov\xfd stav).\n- M\u011bjte na tr\xe9ninku v\u017edy l\xe9k\xe1rni\u010dku s: jednor\xe1zov\xfdmi rukavicemi, steriln\xedm kryt\xedm, elastick\xfdm obinadlem, n\xe1plastmi, fyziologick\xfdm roztokem, chlad\xedc\xedm s\xe1\u010dkem, n\u016f\u017ekami."},{id:'fa-concussion',title:'Ot\u0159es mozku (\xfader do hlavy)',summary:'P\u0159\xedznaky: bolest hlavy, zmatenost, z\xe1vrat\u011b, nevolnost, ztr\xe1ta pam\u011bti, spavost, citlivost na sv\u011btlo nebo hluk, zm\u011bny chov\xe1n\xed, nerovnom\u011brn\xe9 zorni\u010dky.',tags:['Hlava','155'],content:"P\u0159\xedznaky: bolest hlavy, zmatenost, z\xe1vrat\u011b, nevolnost, ztr\xe1ta pam\u011bti, spavost, citlivost na sv\u011btlo nebo hluk, zm\u011bny chov\xe1n\xed, nerovnom\u011brn\xe9 zorni\u010dky.\n\nPostup:\n1. Okam\u017eit\u011b p\u0159eru\u0161te aktivitu a vy\u0159a\u010fte d\xedt\u011b z tr\xe9ninku.\n2. Ulo\u017ete d\xedt\u011b do klidov\xe9 polohy, kontrolujte v\u011bdom\xed.\n3. Sledujte p\u0159\xedznaky \u2014 zeptejte se na jm\xe9no, co dnes d\u011blali, jak se c\xedt\xed.\n4. Nechte d\xedt\u011b pod dohledem dosp\u011bl\xe9 osoby po celou dobu.\n5. V\u017edy kontaktujte rodi\u010de. Doporu\u010dte l\xe9ka\u0159sk\xe9 vy\u0161et\u0159en\xed (ide\xe1ln\u011b do 72 hodin).\n6. D\xedt\u011b se NESM\xcd vr\xe1tit do tr\xe9ninku ten sam\xfd den. N\xe1vrat ke sportu pouze postupn\u011b a se souhlasem l\xe9ka\u0159e.\n\n\u010cerven\xe9 p\u0159\xedznaky \u2014 VOLEJTE IHNED 155:\n- Ztr\xe1ta v\u011bdom\xed (i kr\xe1tk\xe1)\n- Opakovan\xe9 zvracen\xed\n- Z\xe1chvaty / k\u0159e\u010de\n- Siln\xe1 nebo zhor\u0161uj\xedc\xed se bolest hlavy\n- V\xfdtok z nosu nebo u\u0161\xed (\u010dir\xe1 tekutina nebo krev)\n- Zhor\u0161uj\xedc\xed se zmatenost nebo chov\xe1n\xed\n\nPozn\xe1mka: D\u0159\xedv\u011bj\u0161\xed rada \u201ened\xe1vejte d\xedt\u011bti sp\xe1t po \xfaderu do hlavy\" je p\u0159ekonan\xe1. Podle aktu\xe1ln\xedch doporu\u010den\xed (ERC 2025) sp\xe1nek nen\xed \u0161kodliv\xfd, ale d\xedt\u011b by m\u011blo b\xfdt pravideln\u011b kontrolov\xe1no (ka\u017ed\xe9 2\u20133 hodiny v prvn\xedch 24 hodin\xe1ch)."},{id:'fa-spine',title:'Poran\u011bn\xed p\xe1te\u0159e',summary:'P\u0159\xedznaky: bolest v z\xe1dech nebo krku, necitlivost, slabost \u010di brn\u011bn\xed v kon\u010detin\xe1ch, pot\xed\u017ee s pohybem.',tags:['P\xe1te\u0159','155'],content:"P\u0159\xedznaky: bolest v z\xe1dech nebo krku, necitlivost, slabost \u010di brn\u011bn\xed v kon\u010detin\xe1ch, pot\xed\u017ee s pohybem.\n\nPostup:\n1. Neh\xfdbejte se zran\u011bn\xfdm, pokud to nen\xed nezbytn\u011b nutn\xe9 (nap\u0159. ohro\u017een\xed dal\u0161\xedm nebezpe\u010d\xedm).\n2. Stabilizujte hlavu a krk v poloze, v jak\xe9 se nach\xe1zej\xed \u2014 dr\u017ete ob\u011bma rukama, zabra\u0148te jak\xe9mukoli pohybu.\n3. Okam\u017eit\u011b volejte 155 / 112.\n4. Pokud d\xedt\u011b ned\xfdch\xe1 a le\u017e\xed na b\u0159i\u0161e, velmi opatrn\u011b oto\u010dte na z\xe1da technikou \u201elog roll\" (cel\xe9 t\u011blo najednou, bez rotace p\xe1te\u0159e) a zahajte KPR.\n5. Udr\u017eujte d\xedt\u011b v klidu, pr\u016fb\u011b\u017en\u011b kontrolujte d\xfdch\xe1n\xed a v\u011bdom\xed.\n6. Kontaktujte rodi\u010de.\n\nPozn\xe1mka dle ERC 2025: Omezen\xed pohybu kr\u010dn\xed p\xe1te\u0159e (cervical spinal motion restriction) by m\u011bli prov\xe1d\u011bt zejm\xe9na vy\u0161kolen\xed z\xe1chran\xe1\u0159i. Laik by m\u011bl p\u0159edev\u0161\xedm zabr\xe1nit jak\xe9mukoli zbyte\u010dn\xe9mu pohybu a zajistit stabilizaci do p\u0159\xedjezdu z\xe1chranky."},{id:'fa-fracture',title:'Zlomenina',summary:'P\u0159\xedznaky: siln\xe1 bolest, otok, deformace, neschopnost kon\u010detinu pou\u017e\xedvat, p\u0159\xedpadn\u011b nep\u0159irozen\xe1 poloha.',tags:['Kon\u010detina','155'],content:"P\u0159\xedznaky: siln\xe1 bolest, otok, deformace, neschopnost kon\u010detinu pou\u017e\xedvat, p\u0159\xedpadn\u011b nep\u0159irozen\xe1 poloha.\n\nPostup:\n1. Kon\u010detinou neh\xfdbejte \u2014 nechte ji v poloze, ve kter\xe9 je.\n2. Imobilizujte dlahou nebo improvizovan\u011b (pevn\u011b srolovan\xe9 noviny, prkno, fixace ke zdrav\xe9 kon\u010detin\u011b). Znehybn\u011bte kloub nad i pod m\xedstem zlomeniny.\n3. P\u0159ilo\u017ete led (p\u0159es l\xe1tku) na max. 15\u201320 minut \u2014 nikdy p\u0159\xedmo na k\u016f\u017ei.\n4. P\u0159i otev\u0159en\xe9 zlomenin\u011b (kost pronik\xe1 k\u016f\u017e\xed) p\u0159ekryjte r\xe1nu steriln\xedm kryt\xedm. NEPOKOU\u0160EJTE se kost narovnat ani zasouvat zp\u011bt.\n5. Sledujte prokrven\xed za m\xedstem poran\u011bn\xed \u2014 barva prst\u016f (blednut\xed = \u0161patn\xe9), teplota, citlivost.\n6. Volejte 155. Kontaktujte rodi\u010de.\n7. Zaznamenejte \u010das \xfarazu a okolnosti pro z\xe1chran\xe1\u0159e.\n8. Uklid\u0148ujte d\xedt\u011b \u2014 stres a panika bolest subjektivn\u011b zhor\u0161uj\xed."},{id:'fa-sprain-contusion',title:'Podvrtnut\xed / nara\u017eenina',summary:'P\u0159\xedznaky podvrtnut\xed: bolest, otok, omezen\xfd pohyb, n\u011bkdy mod\u0159ina. P\u0159\xedznaky nara\u017eeniny: bolest, otok, mod\u0159ina, pohyblivost omezen\xe1, ale zachovan\xe1.',tags:['RICE','Chlazen\xed'],content:"P\u0159\xedznaky podvrtnut\xed: bolest, otok, omezen\xfd pohyb, n\u011bkdy mod\u0159ina. P\u0159\xedznaky nara\u017eeniny: bolest, otok, mod\u0159ina, pohyblivost omezen\xe1, ale zachovan\xe1.\n\nPostup:\n1. Okam\u017eit\u011b zastavte cvi\u010den\xed a posa\u010fte d\xedt\u011b. Zklidn\u011bte ho.\n2. Chra\u0148te poran\u011bnou oblast \u2014 zabra\u0148te dal\u0161\xedmu pohybu (band\xe1\u017e, dlaha, nebo podep\u0159ete rukou).\n3. Zvedn\u011bte kon\u010detinu nad \xfarove\u0148 srdce \u2014 pom\xe1h\xe1 sn\xed\u017eit otok.\n4. P\u0159ilo\u017ete kompresn\xed obvaz (elastick\xe9 obinadlo) \u2014 pevn\u011b, ale ne p\u0159\xedli\u0161 uta\u017een\u011b. Kontrolujte prsty (barva, teplota, citlivost) \u2014 pokud b\u011blaj\xed nebo mraven\u010d\xed, povolte.\n5. Chlazen\xed: pokud m\xe1te k dispozici led nebo chlad\xedc\xed s\xe1\u010dek, p\u0159ilo\u017ete p\u0159es l\xe1tku na max. 15\u201320 minut. Neaplikujte led p\u0159\xedmo na k\u016f\u017ei.\n6. P\u0159i siln\xe9 bolesti, v\xfdrazn\xe9m otoku, deformaci nebo neschopnosti zat\xed\u017eit kon\u010detinu kontaktujte rodi\u010de a doporu\u010dte l\xe9ka\u0159sk\xe9 vy\u0161et\u0159en\xed.\n7. P\u0159i nara\u017eenin\u011b: p\u0159ilo\u017ete led na 15\u201320 minut, opakujte po hodin\u011b. P\u0159i p\u0159etrv\xe1vaj\xedc\xedch pot\xed\u017e\xedch (siln\xe1 bolest, nemo\u017enost pohybu) doporu\u010dte vy\u0161et\u0159en\xed.\n\nPozn\xe1mka: Klasick\xfd RICE protokol (klid, led, komprese, elevace) je st\xe1le vhodn\xfd pro okam\u017eitou prvn\xed pomoc na tr\xe9ninku. Nov\u011bj\u0161\xed doporu\u010den\xed (PEACE & LOVE, 2019/2025) upozor\u0148uj\xed, \u017ee \xfapln\xfd klid a nadm\u011brn\xe9 chlazen\xed mohou zpomalovat hojen\xed. V kontextu akutn\xed pomoci na tr\xe9ninku ale chlazen\xed pro \xfalevu od bolesti z\u016fst\xe1v\xe1 rozumn\xfdm krokem. D\u016fle\u017eit\xe9 je neaplikovat led d\xe9le ne\u017e 20 minut a po prvn\xedm o\u0161et\u0159en\xed p\u0159edat p\xe9\u010di rodi\u010d\u016fm/l\xe9ka\u0159i."},{id:'fa-wound-bleeding',title:'Tr\u017en\xe1 r\xe1na / od\u0159enina / krv\xe1cen\xed',summary:'P\u0159\xedznaky: viditeln\xe1 r\xe1na, krv\xe1cen\xed (m\xedrn\xe9 a\u017e siln\xe9), bolest.',tags:['Krv\xe1cen\xed','Rukavice'],content:"P\u0159\xedznaky: viditeln\xe1 r\xe1na, krv\xe1cen\xed (m\xedrn\xe9 a\u017e siln\xe9), bolest.\n\nPostup:\n1. Nasa\u010fte si ochrann\xe9 rukavice z l\xe9k\xe1rni\u010dky.\n2. Vypl\xe1chn\u011bte r\xe1nu \u010distou vodou nebo fyziologick\xfdm roztokem. Nepou\u017e\xedvejte peroxid ani alkohol \u2014 dr\xe1\u017ed\xed tk\xe1\u0148 a zpomaluje hojen\xed.\n3. Pokud r\xe1na krv\xe1c\xed, stla\u010dte ji p\u0159\xedmo steriln\xedm obvazem a dr\u017ete st\xe1l\xfd, pevn\xfd tlak po dobu 3\u20135 minut. Neodtrh\xe1vejte obvaz \u2014 pokud prosakuje, p\u0159idejte dal\u0161\xed vrstvu.\n4. Po zastaven\xed krv\xe1cen\xed p\u0159elepte n\xe1plast\xed nebo steriln\xedm kryt\xedm.\n5. P\u0159i hlubok\xe9 r\xe1n\u011b, viditeln\xe9 tukov\xe9 tk\xe1ni \u010di svalu, zasekl\xe9m ciz\xedm p\u0159edm\u011btu (NEVYTAHUJTE!) nebo r\xe1n\u011b del\u0161\xed ne\u017e 1 cm \u2014 volejte 155.\n\nMasivn\xed / \u017eivot ohro\u017euj\xedc\xed krv\xe1cen\xed (dle ERC 2025):\n1. P\u0159ilo\u017ete pevn\xfd p\u0159\xedm\xfd manu\xe1ln\xed tlak na krv\xe1cej\xedc\xed m\xedsto.\n2. Pou\u017eijte standardn\xed nebo hemostatick\xfd obvaz p\u0159\xedmo na r\xe1nu, pot\xe9 na n\u011bj zatla\u010dte.\n3. Pokud krv\xe1cen\xed na kon\u010detin\u011b neust\xe1v\xe1, zva\u017ete p\u0159ilo\u017een\xed za\u0161krcovadla (turniketu) 5\u20137 cm nad r\xe1nu (ne p\u0159es kloub). Zapi\u0161te \u010das p\u0159ilo\u017een\xed.\n4. Volejte 155.\n\nPozn\xe1mka: U jak\xe9koli otev\u0159en\xe9 r\xe1ny ov\u011b\u0159te, zda m\xe1 d\xedt\u011b platn\xe9 o\u010dkov\xe1n\xed proti tetanu. V\u017edy informujte rodi\u010de."},{id:'fa-choking',title:'Du\u0161en\xed (ciz\xed t\u011bleso v d\xfdchac\xedch cest\xe1ch)',summary:'P\u0159\xedznaky: neschopnost d\xfdchat nebo mluvit, modr\xe9 rty, lap\xe1n\xed po dechu, ka\u0161el (pokud \u010d\xe1ste\u010dn\xe1 obstrukce).',tags:['D\xfdch\xe1n\xed','155'],content:"P\u0159\xedznaky: neschopnost d\xfdchat nebo mluvit, modr\xe9 rty, lap\xe1n\xed po dechu, ka\u0161el (pokud \u010d\xe1ste\u010dn\xe1 obstrukce).\n\nPostup:\n1. Pokud d\xedt\u011b ka\u0161le \u2014 povzbuzujte ho ke ka\u0161li. Ka\u0161el je nej\xfa\u010dinn\u011bj\u0161\xed zp\u016fsob odstran\u011bn\xed t\u011blesa. Nezasahujte, dokud je ka\u0161el \xfa\u010dinn\xfd.\n2. Pokud d\xedt\u011b NEM\u016e\u017dE ka\u0161lat, mluvit ani d\xfdchat \u2014 zahajte:\n   - U d\u011bt\xed nad 1 rok a dosp\u011bl\xfdch: 5 \xfader\u016f do zad mezi lopatky (dlan\xed, d\xedt\u011b m\xedrn\u011b p\u0159edklon\u011bn\xe9) \u2192 pokud nepom\xe1h\xe1 \u2192 5 stla\u010den\xed nadb\u0159i\u0161ku (Heimlich\u016fv man\xe9vr).\n   - U kojenc\u016f do 1 roku: 5 \xfader\u016f do zad \u2192 5 stla\u010den\xed hrudn\xedku (NE b\u0159icha \u2014 riziko poran\u011bn\xed).\n3. St\u0159\xeddejte 5 \xfader\u016f do zad a 5 stla\u010den\xed, dokud t\u011bleso nevyjde nebo dokud d\xedt\u011b neztrat\xed v\u011bdom\xed.\n4. Pokud d\xedt\u011b ztrat\xed v\u011bdom\xed \u2014 polo\u017ete na zem, volejte 155/112 a zahajte KPR (za\u010dn\u011bte kompresemi).\n5. I po \xfasp\u011b\u0161n\xe9m odstran\u011bn\xed p\u0159ek\xe1\u017eky v\u017edy vyhledejte l\xe9ka\u0159skou kontrolu (riziko poran\u011bn\xed d\xfdchac\xedch cest nebo vnit\u0159n\xedch org\xe1n\u016f)."},{id:'fa-winded',title:'Vyra\u017een\xfd dech',summary:'P\u0159\xedznaky: kr\xe1tkodob\xe1 neschopnost d\xfdchat, bolest v oblasti hrudn\xedku nebo b\u0159icha, panika.',tags:['D\xfdch\xe1n\xed'],content:"P\u0159\xedznaky: kr\xe1tkodob\xe1 neschopnost d\xfdchat, bolest v oblasti hrudn\xedku nebo b\u0159icha, panika.\n\nPostup:\n1. Uklidn\u011bte d\xedt\u011b \u2014 vysv\u011btlete, \u017ee se dech vr\xe1t\xed.\n2. Instrukujte k pomal\xe9mu, hlubok\xe9mu d\xfdch\xe1n\xed \u2014 n\xe1dech nosem, v\xfddech \xfasty.\n3. Nechte ho sed\u011bt nebo le\u017eet v pohodln\xe9 poloze (m\xedrn\xfd p\u0159edklon \u010dasto pom\xe1h\xe1).\n4. Dech se v\u011bt\u0161inou vr\xe1t\xed do norm\xe1lu b\u011bhem 1\u20133 minut.\n5. Pokud pot\xed\u017ee s d\xfdch\xe1n\xedm p\u0159etrv\xe1vaj\xed d\xe9le ne\u017e 5 minut nebo se zhor\u0161uj\xed \u2014 volejte 155."},{id:'fa-fainting',title:'Mdloba / slabost',summary:'P\u0159\xedznaky: bledost, z\xe1vrat\u011b, pocen\xed, rozmazan\xe9 vid\u011bn\xed, ztr\xe1ta v\u011bdom\xed.',tags:['V\u011bdom\xed'],content:"P\u0159\xedznaky: bledost, z\xe1vrat\u011b, pocen\xed, rozmazan\xe9 vid\u011bn\xed, ztr\xe1ta v\u011bdom\xed.\n\nPostup:\n1. Polo\u017ete d\xedt\u011b na z\xe1da a zvedn\u011bte nohy nad \xfarove\u0148 srdce (podlo\u017ete batohem, \u017e\xedn\u011bnkou).\n2. Uvoln\u011bte oble\u010den\xed kolem krku a pasu, zajist\u011bte p\u0159\xedsun \u010derstv\xe9ho vzduchu.\n3. Pokud je d\xedt\u011b v bezv\u011bdom\xed, ale norm\xe1ln\u011b d\xfdch\xe1 \u2014 ulo\u017ete do stabilizovan\xe9 polohy na boku (recovery position dle ERC 2025).\n4. Pokud NED\xddCH\xc1 norm\xe1ln\u011b \u2014 zahajte resuscitaci: u d\u011bt\xed 5 \xfavodn\xedch vdech\u016f, pot\xe9 pom\u011br 15:2 (komprese:vdechy). Volejte 155.\n5. Po probuzen\xed nab\xeddn\u011bte vodu po mal\xfdch dou\u0161c\xedch.\n6. P\u0159ed n\xe1vratem do tr\xe9ninku po\u010dkejte alespo\u0148 30 minut a sledujte stav.\n7. P\u0159i opakovan\xfdch mdlob\xe1ch doporu\u010dte rodi\u010d\u016fm l\xe9ka\u0159sk\xe9 vy\u0161et\u0159en\xed."},{id:'fa-asthma',title:'Astmatick\xfd z\xe1chvat',summary:'P\u0159\xedznaky: obt\xed\u017en\xe9 d\xfdch\xe1n\xed, p\xedsk\xe1n\xed p\u0159i v\xfddechu, ka\u0161el, nemo\u017enost mluvit celou v\u011btu, \xfazkost.',tags:['D\xfdch\xe1n\xed','L\xe9ky'],content:"P\u0159\xedznaky: obt\xed\u017en\xe9 d\xfdch\xe1n\xed, p\xedsk\xe1n\xed p\u0159i v\xfddechu, ka\u0161el, nemo\u017enost mluvit celou v\u011btu, \xfazkost.\n\nPostup:\n1. Posa\u010fte d\xedt\u011b vzp\u0159\xedmen\u011b \u2014 m\xedrn\xfd p\u0159edklon, ruce op\u0159en\xe9 o kolena.\n2. Zklidn\u011bte d\xedt\u011b \u2014 stres zhor\u0161uje d\xfdchac\xed obt\xed\u017ee.\n3. Pokud m\xe1 d\xedt\u011b sv\u016fj \xfalevov\xfd inhal\xe1tor (typicky salbutamol), pomozte mu ho pou\u017e\xedt.\n4. Pokud se stav nezlep\u0161\xed do 5 minut nebo se zhor\u0161uje (nem\u016f\u017ee mluvit celou v\u011btu, modr\xe9 rty, vtahov\xe1n\xed mezi\u017eebern\xedch prostor\u016f) \u2014 volejte 155.\n5. P\u0159ed tr\xe9ninkem v\u017edy zjist\u011bte od rodi\u010d\u016f, zda m\xe1 d\xedt\u011b astma a kde je jeho inhal\xe1tor."},{id:'fa-anaphylaxis',title:'Alergick\xe1 reakce / anafylaxe',summary:'P\u0159\xedznaky: kop\u0159ivka, otok obli\u010deje/rt\u016f/jazyka, obt\xed\u017en\xe9 d\xfdch\xe1n\xed, sv\xedr\xe1n\xed v krku, z\xe1vrat\u011b, rychl\xfd pokles tlaku.',tags:['Alergie','155'],content:"P\u0159\xedznaky: kop\u0159ivka, otok obli\u010deje/rt\u016f/jazyka, obt\xed\u017en\xe9 d\xfdch\xe1n\xed, sv\xedr\xe1n\xed v krku, z\xe1vrat\u011b, rychl\xfd pokles tlaku.\n\nPostup:\n1. Pokud m\xe1 d\xedt\u011b p\u0159edepsan\xfd adrenalinov\xfd autoinjektor (EpiPen / Jext), pomozte mu ho aplikovat do vn\u011bj\u0161\xed strany stehna (i p\u0159es oble\u010den\xed).\n2. Volejte 155.\n3. Polo\u017ete d\xedt\u011b na z\xe1da se zvednut\xfdmi nohami. Pokud zvrac\xed nebo m\xe1 obt\xed\u017en\xe9 d\xfdch\xe1n\xed, posa\u010fte ho.\n4. Kontaktujte rodi\u010de.\n5. P\u0159ed ka\u017edou sezonou zjist\u011bte od rodi\u010d\u016f alergie d\u011bt\xed a kde maj\xed l\xe9ky."},{id:'fa-nosebleed',title:'Krv\xe1cen\xed z nosu',summary:'Posa\u010fte d\xedt\u011b a m\xedrn\u011b mu naklo\u0148te hlavu DOP\u0158EDU.',tags:['Krv\xe1cen\xed'],content:"Postup:\n1. Posa\u010fte d\xedt\u011b a m\xedrn\u011b mu naklo\u0148te hlavu DOP\u0158EDU (NE dozadu \u2014 krev by tekla do \u017ealudku a d\xedt\u011b by mohlo zvracet).\n2. Stiskn\u011bte m\u011bkkou \u010d\xe1st nosu (pod kost\u011bn\xfdm h\u0159betem) a dr\u017ete 10\u201315 minut bez p\u0159eru\u0161en\xed.\n3. D\xedt\u011b a\u0165 d\xfdch\xe1 \xfasty.\n4. Po zastaven\xed krv\xe1cen\xed: 2 hodiny se nesm\xed smrkat, vyh\xfdbat se fyzick\xe9 n\xe1maze.\n5. Pokud krv\xe1cen\xed neust\xe1v\xe1 po 20 minut\xe1ch \u2014 volejte 155."},{id:'fa-heatstroke',title:'Tepeln\xfd \xfapal / p\u0159eh\u0159\xe1t\xed',summary:'P\u0159\xedznaky: hork\xe1 a such\xe1 k\u016f\u017ee, zmatenost, bolest hlavy, nevolnost, teplota nad 40 \xb0C.',tags:['Horko','155'],content:"P\u0159\xedznaky: hork\xe1 a such\xe1 k\u016f\u017ee, zmatenost, bolest hlavy, nevolnost, teplota nad 40 \xb0C.\n\nPostup:\n1. P\u0159esu\u0148te d\xedt\u011b do st\xednu nebo chladn\xe9 m\xedstnosti.\n2. Svl\xe9kn\u011bte p\u0159ebyte\u010dn\xe9 oble\u010den\xed.\n3. Aktivn\u011b chla\u010fte \u2014 mokr\xe9 hadry na krk, \u010delo, podpa\u017e\xed, t\u0159\xedsla. Pokud je k dispozici ventil\xe1tor, pou\u017eijte ho.\n4. Dejte p\xedt chladnou (ne ledovou) vodu po mal\xfdch dou\u0161c\xedch.\n5. Pokud se objev\xed zmatenost, zvracen\xed, ztr\xe1ta v\u011bdom\xed nebo teplota nad 40 \xb0C \u2014 volejte 155. Jde o \u017eivot ohro\u017euj\xedc\xed stav."},{id:'fa-kit-checklist',title:'Kontroln\xed seznam l\xe9k\xe1rni\u010dky pro tren\xe9ra',summary:'P\u0159ed ka\u017ed\xfdm tr\xe9ninkem zkontrolujte, zda m\xe1te v\u0161e pot\u0159ebn\xe9.',tags:['L\xe9k\xe1rni\u010dka'],content:"P\u0159ed ka\u017ed\xfdm tr\xe9ninkem zkontrolujte, zda m\xe1te:\n- Jednor\xe1zov\xe9 rukavice (min. 4 p\xe1ry)\n- Steriln\xed obvazy a kryt\xed (r\u016fzn\xe9 velikosti)\n- Elastick\xe9 obinadlo\n- N\xe1plasti (r\u016fzn\xe9 velikosti)\n- Fyziologick\xfd roztok (v\xfdplach ran)\n- Chlad\xedc\xed s\xe1\u010dek (instant)\n- N\u016f\u017eky\n- Z\xe1chrann\xe1 (izotermick\xe1) f\xf3lie\n- Resuscita\u010dn\xed rou\u0161ka\n- Kontakty na rodi\u010de a seznam alergi\xed/zdravotn\xedch omezen\xed d\u011bt\xed"}]},{key:'methodology',title:'Metodika u\u010den\xed',subtitle:'Jak spr\xe1vn\u011b u\u010dit nov\xe9 pohyby',icon:'book-open',accent:'#8B1DFF',items:[{id:'me-progressive-learning',title:'Princip progresivn\xedho u\u010den\xed',summary:'V\u017edy za\u010dn\u011bte s nejjednodu\u0161\u0161\xed variantou triku (precision na zemi \u2192 n\xedzk\xe1 p\u0159ek\xe1\u017eka \u2192 vy\u0161\u0161\xed).',content:"1. V\u017edy za\u010dn\u011bte s nejjednodu\u0161\u0161\xed variantou triku (precision na zemi \u2192 n\xedzk\xe1 p\u0159ek\xe1\u017eka \u2192 vy\u0161\u0161\xed).\n2. D\xedt\u011b mus\xed zvl\xe1dnout pohyb 5\xd7 za sebou bez chyby, ne\u017e postoup\xed na vy\u0161\u0161\xed \xfarove\u0148.\n3. P\u0159i strachu se vra\u0165te o krok zp\u011bt a zopakujte. Strach je p\u0159irozen\xe1 ochrana, ne slabost.\n4. Nikdy netla\u010dte na v\xfd\u0161ku/obt\xed\u017enost \u2014 riziko zran\u011bn\xed v\xfdrazn\u011b p\u0159evy\u0161uje p\u0159\xednos.\n5. Dr\u017ete se pravidla: nejd\u0159\xedv kontrola, pak rychlost, pak styl."},{id:'me-spotting',title:'Dopomoc (spotting)',summary:'St\u016fjte v\u017edy v z\xf3n\u011b dopadu, ne v z\xf3n\u011b rozjezdu.',content:"1. St\u016fjte v\u017edy v z\xf3n\u011b dopadu, ne v z\xf3n\u011b rozjezdu.\n2. Dr\u017ete ruku v \xfarovni bok\u016f d\xedt\u011bte \u2014 tam je jeho t\u011b\u017ei\u0161t\u011b.\n3. P\u0159i saltu zezadu jist\u011bte za z\xe1da a ky\u010dle, p\u0159i saltu dop\u0159edu za ramena a b\u0159icho.\n4. Vysv\u011btlete d\xedt\u011bti, kde va\u0161e ruka bude \u2014 mus\xed v\xe1m v\u011b\u0159it. \u0158ekn\u011bte: \u201eBudu t\u011b dr\u017eet tady, dokud ne\u0159eknu jinak.\"\n5. Postupn\u011b dopomoc sni\u017eujte, ale neoznamujte to p\u0159edem, dokud nem\xe1te jistotu, \u017ee zvl\xe1dne samo.\n6. Nikdy nestahujte dopomoc n\xe1hle \u2014 plynul\xe9 sni\u017eov\xe1n\xed buduje d\u016fv\u011bru."},{id:'me-feedback',title:'Konstruktivn\xed zp\u011btn\xe1 vazba',summary:'Za\u010dn\u011bte v\u017edy pozitivem \u2014 co se povedlo (\u201eSuper, \u017ee ses rozhodl sko\u010dit!").',content:"1. Za\u010dn\u011bte v\u017edy pozitivem \u2014 co se povedlo (\u201eSuper, \u017ee ses rozhodl sko\u010dit!\").\n2. Konkr\xe9tn\u011b \u0159ekn\u011bte, co zlep\u0161it (\u201eRuce jsi dal moc dop\u0159edu \u2014 p\u0159\xed\u0161t\u011b je dr\u017e u t\u011bla\").\n3. Uka\u017ete nebo p\u0159edve\u010fte spr\xe1vn\xe9 proveden\xed \u2014 vizu\xe1ln\xed uk\xe1zka funguje l\xe9pe ne\u017e slova.\n4. Nechte d\xedt\u011b zkusit znovu okam\u017eit\u011b, dokud m\xe1 motivaci. Po 3 pokusech bez zlep\u0161en\xed ud\u011blejte pauzu.\n5. Vyhn\u011bte se srovn\xe1v\xe1n\xed s ostatn\xedmi d\u011btmi \u2014 srovn\xe1vejte jen s jeho vlastn\xedm minul\xfdm v\xfdkonem."},{id:'me-fear',title:'Pr\xe1ce se strachem',summary:'Nikdy se d\xedt\u011bti nesm\u011bjte a nezesm\u011b\u0161\u0148ujte ho p\u0159ed skupinou. Strach je norm\xe1ln\xed a m\xe1 sv\xe9 m\xedsto.',content:"1. Nikdy se d\xedt\u011bti nesm\u011bjte a nezesm\u011b\u0161\u0148ujte ho p\u0159ed skupinou. Strach je norm\xe1ln\xed a m\xe1 sv\xe9 m\xedsto.\n2. Rozlo\u017ete trik na men\u0161\xed kroky, aby d\xedt\u011b c\xedtilo postupn\xfd \xfasp\u011bch.\n3. Pou\u017eijte m\u011bkk\xe9 podlo\u017eky, \u017e\xedn\u011bnky, sn\xed\u017een\xe9 p\u0159ek\xe1\u017eky \u2014 fyzick\xe1 bezpe\u010dnost sni\u017euje psychick\xfd strach.\n4. Nechte d\xedt\u011b rozhodnout, kdy je p\u0159ipraveno \u2014 nikdy netla\u010dte. Nab\xeddn\u011bte: \u201eChce\u0161 to zkusit, nebo je\u0161t\u011b jednou n\xe1cvik?\"\n5. Pochvalte ka\u017ed\xfd pokus, i ne\xfasp\u011b\u0161n\xfd \u2014 d\u016fle\u017eit\xe1 je odvaha, ne v\xfdsledek.\n6. Pokud d\xedt\u011b opakovan\u011b odm\xedt\xe1, respektujte to a nab\xeddn\u011bte alternativu."},{id:'me-group',title:'Veden\xed skupiny 8\u201312 d\u011bt\xed',summary:'Na za\u010d\xe1tku jasn\u011b \u0159ekn\u011bte pravidla a co dnes budete d\u011blat (max. 2 minuty).',content:"1. Na za\u010d\xe1tku jasn\u011b \u0159ekn\u011bte pravidla a co dnes budete d\u011blat (max. 2 minuty).\n2. Rozd\u011blte skupinu do stanic s rotac\xed po 5\u20137 minut\xe1ch.\n3. V\u017edy m\u011bjte p\u0159ehled o v\u0161ech d\u011btech \u2014 nikdy nest\u016fjte z\xe1dy k \u017e\xe1dn\xe9 skupin\u011b.\n4. Nejaktivn\u011bj\u0161\xed d\xedt\u011b postavte vedle nejm\xe9n\u011b aktivn\xedho \u2014 p\u0159irozen\u011b si pom\xe1haj\xed.\n5. Vyu\u017eijte \u201ementory\" \u2014 \u0161ikovn\u011bj\u0161\xed d\u011bti mohou ukazovat pohyb mlad\u0161\xedm (buduje to jejich sebev\u011bdom\xed).\n6. Z\xe1v\u011br lekce v\u017edy reflex\xed: co se nau\u010dili, co se povedlo, na co se t\u011b\u0161\xed p\u0159\xed\u0161t\u011b.\n7. Bu\u010fte konzistentn\xed v pravidlech \u2014 co plat\xed prvn\xed tr\xe9nink, plat\xed v\u017edy."}]},{key:'leveling',title:'Levelov\xe1n\xed v parkouru',subtitle:'Systematick\xfd postup od z\xe1klad\u016f po kombinace',icon:'trending-up',accent:'#14C8FF',intro:'Levelov\xe1n\xed p\u0159edstavuje systematick\xfd zp\u016fsob, jak v\xe9st tr\xe9nink od jednoduch\xfdch dovednost\xed a\u017e po komplexn\xed a n\xe1ro\u010dn\xe9 kombinace. Pom\xe1h\xe1 sportovc\u016fm i tren\xe9r\u016fm sledovat progres, motivuje k postupn\xe9mu zlep\u0161ov\xe1n\xed a z\xe1rove\u0148 podporuje bezpe\u010dnost.',items:[{id:'lv-overall',title:'1. Celkov\xe1 \xfarove\u0148',summary:'Zahrnuje dlouhodob\xfd rozvoj dovednost\xed a fyzick\xfdch schopnost\xed praktikanta.',content:"Zahrnuje dlouhodob\xfd rozvoj dovednost\xed a fyzick\xfdch schopnost\xed praktikanta. C\xedlem je celkov\xe9 zlep\u0161en\xed kondice, s\xedly, vytrvalosti, techniky a sebev\u011bdom\xed.\n\nP\u0159\xedklady:\n- Za\u010d\xe1te\u010dn\xedk \u2192 z\xe1kladn\xed pohyby (roll, vault, precision jump)\n- Pokro\u010dil\xfd \u2192 slo\u017eit\u011bj\u0161\xed techniky (kong vault, cat leap, wall run)\n- Expert \u2192 plynul\xe9 kombinace pohyb\u016f ve vysok\xe9 rychlosti, dlouh\xe9 a p\u0159esn\xe9 skoky, akrobatick\xe9 prvky"},{id:'lv-exercise',title:'2. Konkr\xe9tn\xed cvi\u010den\xed',summary:'Zam\u011b\u0159uje se na detailn\xed zlep\u0161ov\xe1n\xed techniky v r\xe1mci jednoho pohybu.',content:"Zam\u011b\u0159uje se na detailn\xed zlep\u0161ov\xe1n\xed techniky v r\xe1mci jednoho pohybu. Praktikant se u\u010d\xed ladit proveden\xed a postupn\u011b zvy\u0161ovat obt\xed\u017enost.\n\nP\u0159\xedklady:\n- Precision jump \u2192 prodlu\u017eov\xe1n\xed vzd\xe1lenosti skoku\n- Vault \u2192 od jednoduch\xe9ho (speed vault) po slo\u017eit\u011bj\u0161\xed (double kong vault)\n- Wall run \u2192 postupn\xe9 zvy\u0161ov\xe1n\xed dosa\u017een\xe9 v\xfd\u0161ky"},{id:'lv-situation',title:'3. Zm\u011bna situace',summary:'Schopnost adaptovat se na r\u016fzn\xe9 prost\u0159ed\xed, podm\xednky a typy p\u0159ek\xe1\u017eek.',content:"Schopnost adaptovat se na r\u016fzn\xe9 prost\u0159ed\xed, podm\xednky a typy p\u0159ek\xe1\u017eek. Kl\xed\u010dov\xfd krok k re\xe1ln\xe9mu pou\u017eit\xed parkouru mimo tr\xe9ninkovou halu.\n\nP\u0159\xedklady:\n- Skoky na r\u016fzn\xfdch povr\u0161\xedch (beton, tr\xe1va, p\xedsek)\n- P\u0159ek\xe1\u017eky v r\u016fzn\xfdch v\xfd\u0161k\xe1ch (n\xedzk\xe1 z\xeddka vs. vysok\xe1 ze\u010f)\n- Tr\xe9nink za odli\u0161n\xfdch podm\xednek (mokro, sucho, r\u016fzn\xe9 ro\u010dn\xed obdob\xed)"},{id:'lv-variations',title:'4. Variace a kombinace',summary:'Vy\u0161\u0161\xed stupe\u0148 dovednost\xed \u2014 propojen\xed v\xedce technik do plynul\xfdch sekvenc\xed.',content:"Vy\u0161\u0161\xed stupe\u0148 dovednost\xed \u2014 propojen\xed v\xedce technik do plynul\xfdch sekvenc\xed. Zvy\u0161uje komplexnost, koordinaci a kreativitu.\n\nP\u0159\xedklady:\n- Kong vault \u2192 navazuje precision jump\n- Wall run \u2192 p\u0159echod do cat leap na druhou st\u011bnu\n- S\xe9rie r\u016fzn\xfdch vault\u016f v rychl\xe9m sledu"},{id:'lv-principles',title:'5. Obecn\xe9 principy',summary:'Parkour nen\xed jen o technice, ale i o filozofii tr\xe9ninku a p\u0159\xedstupu k p\u0159ekon\xe1v\xe1n\xed p\u0159ek\xe1\u017eek.',content:"Parkour nen\xed jen o technice, ale i o filozofii tr\xe9ninku a p\u0159\xedstupu k p\u0159ekon\xe1v\xe1n\xed p\u0159ek\xe1\u017eek.\n\nKl\xed\u010dov\xe9 z\xe1sady:\n- Postupn\xe1 progrese \u2192 zvy\u0161ov\xe1n\xed obt\xed\u017enosti krok za krokem, bezpe\u010dn\xfd rozvoj bez zbyte\u010dn\xfdch zran\u011bn\xed\n- Efektivita pohybu \u2192 plynulost, minimalizace zbyte\u010dn\xfdch pohyb\u016f a spot\u0159eby energie\n- Kreativita \u2192 hled\xe1n\xed nov\xfdch cest, kombinac\xed a zp\u016fsob\u016f, jak se pohybovat"},{id:'lv-mario',title:'6. Hern\xed princip \u201eMARIO"',summary:'Metoda, kter\xe1 vyu\u017e\xedv\xe1 princip level\u016f zn\xe1m\xfdch z her.',content:"Metoda, kter\xe1 vyu\u017e\xedv\xe1 princip level\u016f zn\xe1m\xfdch z her.\n- Cvi\u010denci pln\xed \xfakoly na jednotliv\xfdch stanovi\u0161t\xedch (\u201elevelech\") \u2014 od nejjednodu\u0161\u0161\xedch po nejt\u011b\u017e\u0161\xed.\n- Ka\u017ed\xfd level se opakuje, dokud tren\xe9r nerozhodne, \u017ee praktikant m\u016f\u017ee postoupit v\xfd\u0161.\n- Skv\u011ble funguje zejm\xe9na pro d\u011bti 6\u201312 let, proto\u017ee je hrav\xe1, motiva\u010dn\xed a z\xe1rove\u0148 umo\u017e\u0148uje postupnou a bezpe\u010dnou progresi."}]}]},849,[]);
